namespace sv_023f5ec75d834e349f5d687416fd7e7f.Models;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@* Step indicator bar showing progress through the multi-step form *@

<nav class="step-indicator mb-4" aria-label="Form progress">
    <ol class="d-flex list-unstyled justify-content-between position-relative step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = stepIndex < CurrentStep;
            var isFuture = stepIndex > CurrentStep;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => OnStepClick(stepIndex)"
                role="button"
                tabindex="@(isCompleted ? 0 : -1)"
                aria-current="@(isCurrent ? "step" : null)">
                <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <small class="@(isFuture ? "text-muted" : "")">@StepNames[stepIndex]</small>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public List<string> StepNames { get; set; } = [];

    [Parameter]
    public EventCallback<int> OnNavigateToStep { get; set; }

    private async Task OnStepClick(int stepIndex)
    {
        // Only allow clicking completed steps
        if (stepIndex < CurrentStep)
        {
            await OnNavigateToStep.InvokeAsync(stepIndex);
        }
    }
}

@* Step 1: Personal information *@

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" type="text" class="form-control @(Errors.ContainsKey("FullName") ? "is-invalid" : "")"
           @bind="FullName" @bind:event="oninput" />
    @if (Errors.TryGetValue("FullName", out var nameError))
    {
        <div class="invalid-feedback">@nameError</div>
    }
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @(Errors.ContainsKey("Email") ? "is-invalid" : "")"
           @bind="Email" @bind:event="oninput" />
    @if (Errors.TryGetValue("Email", out var emailError))
    {
        <div class="invalid-feedback">@emailError</div>
    }
</div>

<div class="mb-3">
    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control @(Errors.ContainsKey("Phone") ? "is-invalid" : "")"
           @bind="Phone" @bind:event="oninput" />
    @if (Errors.TryGetValue("Phone", out var phoneError))
    {
        <div class="invalid-feedback">@phoneError</div>
    }
</div>

<div class="mb-3">
    <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control @(Errors.ContainsKey("Address") ? "is-invalid" : "")"
              rows="2" @bind="Address" @bind:event="oninput"></textarea>
    @if (Errors.TryGetValue("Address", out var addrError))
    {
        <div class="invalid-feedback">@addrError</div>
    }
</div>

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating…</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private Dictionary<string, string> Errors { get; set; } = new();
    private bool IsValidating { get; set; }

    private async Task HandleNext()
    {
        Errors.Clear();

        if (string.IsNullOrWhiteSpace(FullName))
            Errors["FullName"] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            Errors["Email"] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            Errors["Phone"] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            Errors["Address"] = "Address is required.";

        if (Errors.Count > 0)
            return;

        // Async email validation
        if (ValidateEmail is not null)
        {
            IsValidating = true;
            StateHasChanged();

            var isValid = await ValidateEmail(Email);
            IsValidating = false;

            if (!isValid)
            {
                Errors["Email"] = "Please enter a valid email address.";
                return;
            }
        }

        await FullNameChanged.InvokeAsync(FullName);
        await EmailChanged.InvokeAsync(Email);
        await PhoneChanged.InvokeAsync(Phone);
        await AddressChanged.InvokeAsync(Address);
        await OnNext.InvokeAsync();
    }
}

@* Step 2: Work history with dynamic entry list *@

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="mb-2">
                <label class="form-label">Company Name <span class="text-danger">*</span></label>
                <input type="text" class="form-control @(GetFieldError(index, "Company") != null ? "is-invalid" : "")"
                       value="@entry.Company"
                       @onchange="e => UpdateEntry(index, entry with { Company = e.Value?.ToString() ?? "" })" />
                @if (GetFieldError(index, "Company") is string compErr)
                {
                    <div class="invalid-feedback">@compErr</div>
                }
            </div>

            <div class="mb-2">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control @(GetFieldError(index, "Title") != null ? "is-invalid" : "")"
                       value="@entry.Title"
                       @onchange="e => UpdateEntry(index, entry with { Title = e.Value?.ToString() ?? "" })" />
                @if (GetFieldError(index, "Title") is string titleErr)
                {
                    <div class="invalid-feedback">@titleErr</div>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control @(GetFieldError(index, "StartDate") != null ? "is-invalid" : "")"
                           value="@entry.StartDate.ToString("yyyy-MM-dd")"
                           @onchange="e => UpdateEntry(index, entry with { StartDate = DateTime.Parse(e.Value?.ToString() ?? DateTime.MinValue.ToString()) })" />
                    @if (GetFieldError(index, "StartDate") is string startErr)
                    {
                        <div class="invalid-feedback">@startErr</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control"
                           value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                           disabled="@entry.IsCurrent"
                           @onchange="e => UpdateEntry(index, entry with { EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!) })" />
                    <div class="form-check mt-1">
                        <input class="form-check-input" type="checkbox" id="current-@index"
                               checked="@entry.IsCurrent"
                               @onchange="e => UpdateEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                        <label class="form-check-label" for="current-@index">I currently work here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2"
                          value="@entry.Description"
                          @onchange="e => UpdateEntry(index, entry with { Description = e.Value?.ToString() ?? "" })"></textarea>
            </div>
        </div>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
    <span class="me-1">+</span> Add Another Position
</button>

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">Please fix the errors above before continuing.</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = [];
    [Parameter] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private Dictionary<string, string> Errors { get; set; } = new();

    private string? GetFieldError(int index, string field) =>
        Errors.TryGetValue($"{index}.{field}", out var err) ? err : null;

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
        EntriesChanged.InvokeAsync(Entries);
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var e = Entries[i];
            if (string.IsNullOrWhiteSpace(e.Company))
                Errors[$"{i}.Company"] = "Company name is required.";
            if (string.IsNullOrWhiteSpace(e.Title))
                Errors[$"{i}.Title"] = "Job title is required.";
            if (e.StartDate == default)
                Errors[$"{i}.StartDate"] = "Start date is required.";
        }

        if (Errors.Count > 0)
            return;

        await EntriesChanged.InvokeAsync(Entries);
        await OnNext.InvokeAsync();
    }

    /// <summary>Mutable view-model for a work entry, including the "current job" flag.</summary>
    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }
}

@* Step 3: References (2-3) *@

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var r = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @(GetFieldError(index, "Name") != null ? "is-invalid" : "")"
                           value="@r.Name"
                           @onchange="e => UpdateRef(index, r with { Name = e.Value?.ToString() ?? "" })" />
                    @if (GetFieldError(index, "Name") is string nameErr)
                    {
                        <div class="invalid-feedback">@nameErr</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @(GetFieldError(index, "Relationship") != null ? "is-invalid" : "")"
                           value="@r.Relationship"
                           @onchange="e => UpdateRef(index, r with { Relationship = e.Value?.ToString() ?? "" })" />
                    @if (GetFieldError(index, "Relationship") is string relErr)
                    {
                        <div class="invalid-feedback">@relErr</div>
                    }
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control @(GetFieldError(index, "Email") != null ? "is-invalid" : "")"
                           value="@r.Email"
                           @onchange="e => UpdateRef(index, r with { Email = e.Value?.ToString() ?? "" })" />
                    @if (GetFieldError(index, "Email") is string emailErr)
                    {
                        <div class="invalid-feedback">@emailErr</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control @(GetFieldError(index, "Phone") != null ? "is-invalid" : "")"
                           value="@r.Phone"
                           @onchange="e => UpdateRef(index, r with { Phone = e.Value?.ToString() ?? "" })" />
                    @if (GetFieldError(index, "Phone") is string phoneErr)
                    {
                        <div class="invalid-feedback">@phoneErr</div>
                    }
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < MaxReferences)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        <span class="me-1">+</span> Add Reference
    </button>
}

@if (Errors.Count > 0)
{
    <div class="alert alert-danger">Please fix the errors above before continuing.</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxReferences = 3;

    [Parameter] public List<ReferenceModel> References { get; set; } = [];
    [Parameter] public EventCallback<List<ReferenceModel>> ReferencesChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private Dictionary<string, string> Errors { get; set; } = new();

    private string? GetFieldError(int index, string field) =>
        Errors.TryGetValue($"{index}.{field}", out var err) ? err : null;

    private void UpdateRef(int index, ReferenceModel updated)
    {
        References[index] = updated;
        ReferencesChanged.InvokeAsync(References);
    }

    private void AddReference()
    {
        if (References.Count < MaxReferences)
        {
            References.Add(new ReferenceModel());
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < References.Count; i++)
        {
            var r = References[i];
            if (string.IsNullOrWhiteSpace(r.Name))
                Errors[$"{i}.Name"] = "Name is required.";
            if (string.IsNullOrWhiteSpace(r.Relationship))
                Errors[$"{i}.Relationship"] = "Relationship is required.";
            if (string.IsNullOrWhiteSpace(r.Email))
                Errors[$"{i}.Email"] = "Email is required.";
            if (string.IsNullOrWhiteSpace(r.Phone))
                Errors[$"{i}.Phone"] = "Phone is required.";
        }

        if (Errors.Count > 0)
            return;

        await ReferencesChanged.InvokeAsync(References);
        await OnNext.InvokeAsync();
    }

    public record ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

@* Step 4: Cover letter with character count *@

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label for="coverLetter" class="form-label">Write your cover letter</label>
    <textarea id="coverLetter" class="form-control @(Error != null ? "is-invalid" : "")"
              rows="10"
              maxlength="@MaxLength"
              @bind="CoverLetter"
              @bind:event="oninput"></textarea>
    @if (Error is not null)
    {
        <div class="invalid-feedback">@Error</div>
    }
    <div class="form-text text-end">
        @(CoverLetter?.Length ?? 0) / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? Error { get; set; }

    private async Task HandleNext()
    {
        Error = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            Error = "A cover letter is required.";
            return;
        }

        await CoverLetterChanged.InvokeAsync(CoverLetter);
        await OnNext.InvokeAsync();
    }
}

@using static sv_023f5ec75d834e349f5d687416fd7e7f.Components.JobApplication.WorkHistoryStep
