    [Parameter] public Func<Task<int>>? OnSubmit { get; set; }

    private bool IsSubmitting { get; set; }
    private bool Submitted { get; set; }
    private int ApplicationId { get; set; }
    private string? SubmitError { get; set; }

    private async Task HandleSubmit()
    {
        if (OnSubmit is null) return;

        IsSubmitting = true;
        SubmitError = null;
        StateHasChanged();

        try
        {
            ApplicationId = await OnSubmit();
            Submitted = true;
        }
        catch (Exception ex)
