{"path": "/tmp/sv-023f5ec75d834e349f5d687416fd7e7f/Components/JobApplication/StepIndicator.razor", "file_text": "@* Step indicator bar showing progress through the multi-step form *@

<nav class="step-indicator mb-4" aria-label="Form progress">
    <ol class="d-flex list-unstyled justify-content-between position-relative step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var isCurrent = stepIndex == CurrentStep;
            var isCompleted = stepIndex < CurrentStep;
            var isFuture = stepIndex > CurrentStep;

            <li class="step-item text-center flex-fill @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "future" : "")"
                @onclick="() => OnStepClick(stepIndex)"
                role="button"
                tabindex="@(isCompleted ? 0 : -1)"
                aria-current="@(isCurrent ? "step" : null)">
                <div class="step-circle mx-auto mb-1 @(isCurrent ? "bg-primary text-white" : isCompleted ? "bg-success text-white" : "bg-light text-muted border")">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(stepIndex + 1)</span>
                    }
                </div>
                <small class="@(isFuture ? "text-muted" : "")">@StepNames[stepIndex]</small>
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired]
    public int CurrentStep { get; set; }

    [Parameter, EditorRequired]
    public List<string> StepNames { get; set; } = [];

    [Parameter]
    public EventCallback<int> OnNavigateToStep { get; set; }

    private async Task OnStepClick(int stepIndex)
    {
        // Only allow clicking completed steps
        if (stepIndex < CurrentStep)
        {
            await OnNavigateToStep.InvokeAsync(stepIndex);
        }
    }
}
"}

