arguments.file_text:
@page "/apply"
@rendermode InteractiveServer

@using sv_023f5ec75d834e349f5d687416fd7e7f.Models
@using sv_023f5ec75d834e349f5d687416fd7e7f.Components.JobApplication
@using static sv_023f5ec75d834e349f5d687416fd7e7f.Components.JobApplication.WorkHistoryStep
@using static sv_023f5ec75d834e349f5d687416fd7e7f.Components.JobApplication.ReferencesStep

@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="@_currentStep"
                   StepNames="@_stepNames"
                   OnNavigateToStep="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep @bind-FullName="_fullName"
                              @bind-Email="_email"
                              @bind-Phone="_phone"
                              @bind-Address="_address"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="NextStep" />
            break;

        case 1:
            <WorkHistoryStep @bind-Entries="_workEntries"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 2:
            <ReferencesStep @bind-References="_references"
                            OnNext="NextStep"
                            OnBack="PreviousStep" />
            break;

        case 3:
            <CoverLetterStep @bind-CoverLetter="_coverLetter"
                             OnNext="NextStep"
                             OnBack="PreviousStep" />
            break;

        case 4:
            <ReviewStep FullName="@_fullName"
                        Email="@_email"
                        Phone="@_phone"
                        Address="@_address"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="@_coverLetter"
                        OnBack="PreviousStep"
                        OnEditStep="GoToStep"
                        OnSubmit="SubmitAsync" />
            break;
    }
</div>

@code {
    private int _currentStep;

    private readonly List<string> _stepNames =
    [
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    ];

    // Step 1 state
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";

    // Step 2 state
    private List<WorkEntryModel> _workEntries = [new()];

    // Step 3 state
    private List<ReferenceModel> _references = [new(), new()];

    // Step 4 state
    private string _coverLetter = "";

    private void NextStep() => _currentStep = Math.Min(_currentStep + 1, _stepNames.Count - 1);
    private void PreviousStep() => _currentStep = Math.Max(_currentStep - 1, 0);
    private void GoToStep(int step) => _currentStep = Math.Clamp(step, 0, _stepNames.Count - 1);

    private async Task<int> SubmitAsync()
    {
        var personal = new PersonalInfo(_fullName, _email, _phone, _address);
        var workHistory = new WorkHistory(
            _workEntries.Select(e => new WorkEntry(
                e.Company, e.Title, e.StartDate,
                e.IsCurrent ? null : e.EndDate,
                e.Description
            )).ToList()
        );
        var references = _references.Select(r =>
            new Reference(r.Name, r.Relationship, r.Email, r.Phone)
        ).ToList();

        var application = new JobApplication(personal, workHistory, references, _coverLetter);
        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

.step-list {
    counter-reset: step;
}

.step-item {
    position: relative;
    z-index: 1;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    transition: all 0.2s ease;
}

.step-item.completed {
    cursor: pointer;
}

.step-item.completed:hover .step-circle {
    opacity: 0.8;
}

.step-item.future {
    cursor: default;
}

/* Connector line between steps */
.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: calc(50% + 22px);
    right: calc(-50% + 22px);
    height: 2px;
    background-color: #dee2e6;
    z-index: -1;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

