                       @onchange="e => SetCompany(index, e)" />
                @{ var compErr = GetFieldError(index, "Company"); }
                @if (compErr != null)
                {
                    <div class="invalid-feedback">@compErr</div>
                }
            </div>

            <div class="mb-2">
                <label class="form-label">Job Title <span class="text-danger">*</span></label>
                <input type="text" class="form-control @ValidationCss(index, "Title")"
                       value="@entry.Title"
                       @onchange="e => SetTitle(index, e)" />
                @{ var titleErr = GetFieldError(index, "Title"); }
                @if (titleErr != null)
                {
                    <div class="invalid-feedback">@titleErr</div>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
