    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        Errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            var e = Entries[i];
            if (string.IsNullOrWhiteSpace(e.Company))
                Errors[$"{i}.Company"] = "Company name is required.";
            if (string.IsNullOrWhiteSpace(e.Title))
                Errors[$"{i}.Title"] = "Job title is required.";
            if (e.StartDate == default)
                Errors[$"{i}.StartDate"] = "Start date is required.";
        }

        if (Errors.Count > 0)
            return;

        await EntriesChanged.InvokeAsync(Entries);
        await OnNext.InvokeAsync();
    }

    /// <summary>Mutable view-model for a work entry, including the "current job" flag.</summary>
    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; }
        public DateTime? EndDate { get; set; }
